"""
SubagentMiddleware - Provides spawn_subagent tool for lightweight parallel task execution.

Spawned subagents run a simple tool-calling loop (no full graph/checkpointer).
When a tool_registry + store are configured, subagents get `retrieve_tools`
for dynamic discovery instead of binding all tools upfront.
"""

import asyncio
from collections.abc import Mapping
import time
from typing import Annotated, Any, cast
from uuid import uuid4

from langchain.agents.middleware.types import (
    AgentMiddleware,
    AgentState,
    OmitFromInput,
)
from langchain.tools import InjectedToolCallId
from langchain_core.language_models import LanguageModelLike
from langchain_core.messages import AIMessage, HumanMessage, SystemMessage, ToolMessage
from langchain_core.messages.tool import ToolCall
from langchain_core.runnables import RunnableConfig
from langchain_core.tools import BaseTool, StructuredTool, tool
from langgraph.config import get_stream_writer
from langgraph.prebuilt import InjectedState
from langgraph.store.base import BaseStore
from langgraph.types import Command

from app.agents.prompts.spawn_subagent_prompts import (
    SPAWN_SUBAGENT_DESCRIPTION,
    SPAWN_SUBAGENT_SYSTEM_PROMPT,
)
from app.agents.tools.core.retrieval import get_retrieve_tools_function
from app.agents.tools.core.tool_runtime_config import ToolRuntimeConfig
from app.constants.general import FINISH_TASK_NAME
from app.constants.llm import SUBAGENT_RECURSION_LIMIT
from app.constants.log_tags import LogTag
from app.utils.agent_utils import (
    StreamWriterCallable,
    emit_subagent_tool_calls,
    format_subagent_end_event,
    format_subagent_start_event,
)
from shared.py.wide_events import log

_RETRIEVE_TOOLS_NAME = "retrieve_tools"


class SubagentState(AgentState[Any]):
    """State schema for subagent middleware."""

    active_subagents: Annotated[list[str], OmitFromInput]


class SubagentMiddleware(AgentMiddleware[SubagentState, Any]):
    """Middleware that exposes a spawn_subagent tool for focused subtask execution."""

    state_schema = SubagentState

    def __init__(
        self,
        llm: LanguageModelLike | None = None,
        available_tools: list[BaseTool] | None = None,
        tool_registry: Mapping[str, BaseTool] | None = None,
        max_turns: int = SUBAGENT_RECURSION_LIMIT,
        system_prompt: str = SPAWN_SUBAGENT_SYSTEM_PROMPT,
        excluded_tool_names: set[str] | None = None,
        tool_space: str = "general",
        store: BaseStore | None = None,
        tool_runtime_config: ToolRuntimeConfig | None = None,
    ):
        super().__init__()
        self._llm = llm
        self._available_tools = available_tools or []
        self._tool_registry = tool_registry
        self._max_turns = max_turns
        self._system_prompt = system_prompt
        self._excluded_tools = excluded_tool_names or set()
        self._excluded_tools.add("spawn_subagent")
        self._tool_space = tool_space
        self._store: BaseStore | None = store
        self._tool_runtime_config = (
            tool_runtime_config
            if tool_runtime_config
            else ToolRuntimeConfig(
                initial_tool_names=["read", "bash"],
                enable_retrieve_tools=True,
                include_subagents_in_retrieve=False,
            )
        )

        self.tools = [self._create_spawn_subagent_tool()]

    def _create_spawn_subagent_tool(self):
        middleware = self

        @tool(REDACTED)
        async def spawn_subagent(
            task: str,
            tool_call_id: Annotated[str, InjectedToolCallId],
            selected_tool_ids: Annotated[list[str], InjectedState("selected_tool_ids")],
            config: RunnableConfig,
            context: str = "",
        ) -> Command[Any]:
            """Spawn a subagent to handle a subtask with focused execution."""
            if middleware._llm is None:
                return Command(
                    update={
                        "messages": [
                            ToolMessage(
                                content="Error: Subagent LLM not configured",
                                tool_call_id=tool_call_id,
                                status="error",
                            )
                        ]
                    }
                )

            try:
                # Emit subagent_start/end events for the UI
                sa_id = str(uuid4())
                configurable = config.get("configurable", {})
                parent_sa_id = configurable.get("subagent_id")

                # Surface the task as the subagent's name so the UI shows
                # what's running, not three identical "Subagent" rows.
                spawn_name = (task[:40].rstrip() + "…") if len(task) > 40 else (task or "Subagent")
                try:
                    writer = get_stream_writer()
                    writer(
                        {
                            "subagent_start": format_subagent_start_event(
                                subagent_name=spawn_name,
                                agent_type="spawned",
                                subagent_id=sa_id,
                                tool_category="spawn_subagent",
                                parent_subagent_id=parent_sa_id,
                            )
                        }
                    )
                except Exception:
                    writer = None  # type: ignore[assignment]

                start_time = time.monotonic()
                result = await middleware._execute_subagent(
                    task,
                    context,
                    config,
                    inherited_tool_names=selected_tool_ids,
                    stream_writer=writer,
                    subagent_id=sa_id,
                )

                if writer is not None:
                    duration_ms = int((time.monotonic() - start_time) * 1000)
                    writer(
                        {
                            "subagent_end": format_subagent_end_event(
                                subagent_id=sa_id,
                                duration_ms=duration_ms,
                            )
                        }
                    )

                return Command(
                    update={
                        "messages": [
                            ToolMessage(
                                content=result,
                                tool_call_id=tool_call_id,
                            )
                        ]
                    }
                )
            except asyncio.CancelledError:
                raise
            except Exception as e:
                log.error(f"{LogTag.AGENT} Subagent execution failed: {e}")
                return Command(
                    update={
                        "messages": [
                            ToolMessage(
                                content=f"Subagent error: {e!s}",
                                tool_call_id=tool_call_id,
                                status="error",
                            )
                        ]
                    }
                )

        return spawn_subagent

    def _build_retrieve_tool(
        self,
        config: RunnableConfig,
    ) -> StructuredTool | None:
        """Build a retrieve_tools StructuredTool with pre-bound store/config.

        Returns None if store is not configured.
        """
        if not self._tool_runtime_config.enable_retrieve_tools or self._store is None:
            return None

        store = self._store
        inner_fn = get_retrieve_tools_function(
            tool_space=self._tool_space,
            include_subagents=self._tool_runtime_config.include_subagents_in_retrieve,
        )

        async def retrieve_tools(
            query: str | None = None,
            exact_tool_names: list[str] | None = None,
        ):
            return await inner_fn(
                store=store,
                config=config,
                query=query,
                exact_tool_names=exact_tool_names,
            )

        retrieve_tools.__doc__ = inner_fn.__doc__

        return StructuredTool.from_function(
            coroutine=retrieve_tools,
            name=_RETRIEVE_TOOLS_NAME,
        )

    def _collect_tools(self) -> list[BaseTool]:
        """Collect all eligible tools from available_tools and tool_registry."""
        tools: list[BaseTool] = []

        for t in self._available_tools:
            if hasattr(t, "name") and t.name not in self._excluded_tools:
                tools.append(t)

        if self._tool_registry:
            for name, registry_tool in self._tool_registry.items():
                if name not in self._excluded_tools:
                    tools.append(registry_tool)

        return tools

    def _bind_tools_from_registry(
        self,
        names: list[str],
        tools_by_name: dict[str, BaseTool],
        bound_tool_names: set[str],
    ) -> list[str]:
        """Resolve tool names from registry into tools_by_name. Returns newly bound names."""
        newly_bound: list[str] = []
        if not self._tool_registry:
            return newly_bound

        for name in names:
            if name in bound_tool_names or name in self._excluded_tools:
                continue
            tool_instance = self._tool_registry.get(name)
            if tool_instance is not None:
                tools_by_name[name] = tool_instance
                bound_tool_names.add(name)
                newly_bound.append(name)

        return newly_bound

    async def _execute_subagent(
        self,
        task: str,
        context: str,
        config: RunnableConfig,
        inherited_tool_names: list[str] | None = None,
        stream_writer: StreamWriterCallable | None = None,
        subagent_id: str | None = None,
    ) -> str:
        """Run a lightweight tool-calling loop for the subagent."""
        if self._llm is None:
            raise ValueError("LLM not configured for subagent execution")

        model_configurations = config.get("configurable", {})
        user_id = model_configurations.get("user_id")
        llm: Any = self._llm.with_config(configurable=model_configurations)

        tools_by_name, dynamic, retrieve_tool = self._build_child_toolset(
            config=config,
            inherited_tool_names=inherited_tool_names,
        )
        bound_tool_names: set[str] = set(tools_by_name.keys())

        llm_with_tools = llm.bind_tools(list(tools_by_name.values())) if tools_by_name else llm

        # Build initial messages
        messages: list[Any] = [SystemMessage(content=self._system_prompt)]
        user_content = f"Context:\n{context}\n\nTask:\n{task}" if context else f"Task:\n{task}"
        messages.append(HumanMessage(content=user_content))

        # Tool-calling loop
        for _turn in range(self._max_turns):
            response = cast(AIMessage, await llm_with_tools.ainvoke(messages, config=config))
            messages.append(response)

            if not response.tool_calls:
                return str(response.content) if response.content else "Task completed."

            for tc in response.tool_calls:
                if tc["name"] == FINISH_TASK_NAME:
                    args = tc.get("args", {})
                    result = args.get("result")
                    if result is None:
                        return "Task completed."
                    return str(result)

            regular_calls: list[ToolCall] = []
            for tc in response.tool_calls:
                name = tc["name"]
                tc_id = tc["id"]

                if name == _RETRIEVE_TOOLS_NAME and dynamic and retrieve_tool is not None:
                    try:
                        result = await retrieve_tool.ainvoke(tc["args"])
                        newly_bound = self._bind_tools_from_registry(
                            result.get("tools_to_bind", []),
                            tools_by_name,
                            bound_tool_names,
                        )
                        if newly_bound:
                            log.info(
                                f"{LogTag.AGENT} Subagent bound {len(newly_bound)} tools: {newly_bound}"
                            )
                        content = "\n".join(result.get("response", [])) or "No tools found."
                    except asyncio.CancelledError:
                        raise
                    except Exception as e:
                        log.error(f"{LogTag.AGENT} Subagent retrieve_tools error: {e}")
                        content = f"retrieve_tools error: {e}"

                    messages.append(ToolMessage(content=content, tool_call_id=tc_id, name=name))
                    # Rebind LLM with updated tool set
                    llm_with_tools = llm.bind_tools(list(tools_by_name.values()))
                else:
                    regular_calls.append(tc)

            if not regular_calls:
                continue

            # Emit tool_data for each call so the frontend can show them in the
            # spawned subagent's row before results arrive.
            if stream_writer and subagent_id:
                await emit_subagent_tool_calls(
                    stream_writer, subagent_id, regular_calls, user_id=user_id
                )

            async def _invoke_tool(tc: ToolCall) -> ToolMessage:
                name = tc["name"]
                tc_id = tc["id"]
                if name not in tools_by_name:
                    hint = (
                        " Use retrieve_tools to discover and bind tools first." if dynamic else ""
                    )
                    return ToolMessage(
                        content=f"Unknown tool: {name}.{hint}",
                        tool_call_id=tc_id,
                        name=name,
                        status="error",
                    )
                try:
                    result = await tools_by_name[name].ainvoke(
                        {**tc, "type": "tool_call"}, config=config
                    )
                    result_str = str(result)
                    if stream_writer and subagent_id:
                        stream_writer(
                            {
                                "tool_output": {
                                    "tool_call_id": tc_id or "",
                                    "output": result_str,
                                    "subagent_id": subagent_id,
                                }
                            }
                        )
                    return ToolMessage(content=result_str, tool_call_id=tc_id, name=name)
                except asyncio.CancelledError:
                    raise
                except Exception:
                    log.exception(
                        f"{LogTag.AGENT} Subagent tool invocation failed for tool '{name}' (tool_call_id={tc_id})",
                    )
                    return ToolMessage(
                        content="Tool error: internal failure while executing tool.",
                        tool_call_id=tc_id,
                        name=name,
                        status="error",
                    )

            semaphore = asyncio.Semaphore(8)

            async def _invoke_tool_limited(tc: ToolCall) -> ToolMessage:
                async with semaphore:
                    return await _invoke_tool(tc)

            tool_messages: list[ToolMessage] = await asyncio.gather(
                *[_invoke_tool_limited(tc) for tc in regular_calls]
            )
            messages.extend(tool_messages)

        # Max turns reached — get final answer without tools
        final = await llm.ainvoke(messages, config=config)
        if isinstance(final, AIMessage) and final.content:
            return str(final.content)
        return str(final) if final else "Max turns reached."

    def _build_child_toolset(
        self,
        config: RunnableConfig,
        inherited_tool_names: list[str] | None = None,
    ) -> tuple[dict[str, BaseTool], bool, StructuredTool | None]:
        """Build child subagent tool map from runtime config and parent state."""
        retrieve_tool = self._build_retrieve_tool(config)
        dynamic = retrieve_tool is not None and self._tool_registry is not None

        tools_by_name: dict[str, BaseTool] = {}
        bound_tool_names: set[str] = set()

        # Bind configured initial tools first (regular tools, not special behavior tools).
        self._bind_tools_from_registry(
            self._tool_runtime_config.initial_tool_names,
            tools_by_name,
            bound_tool_names,
        )

        # Inherit tools currently bound by the parent agent in this turn.
        if inherited_tool_names:
            self._bind_tools_from_registry(
                inherited_tool_names,
                tools_by_name,
                bound_tool_names,
            )

        if dynamic and retrieve_tool is not None:
            tools_by_name[_RETRIEVE_TOOLS_NAME] = retrieve_tool

        # If nothing resolved (defensive fallback), bind all eligible tools.
        if not tools_by_name:
            all_tools = self._collect_tools()
            tools_by_name = {t.name: t for t in all_tools}

        return tools_by_name, dynamic, retrieve_tool

    def set_llm(self, llm: LanguageModelLike) -> None:
        self._llm = llm

    def set_store(self, store: BaseStore) -> None:
        self._store = store

    def set_tools(
        self,
        tools: list[BaseTool] | None = None,
        registry: Mapping[str, BaseTool] | None = None,
        excluded_tool_names: set[str] | None = None,
        tool_space: str | None = None,
        tool_runtime_config: ToolRuntimeConfig | None = None,
    ) -> None:
        if tools is not None:
            self._available_tools = tools
        if registry is not None:
            self._tool_registry = registry
        if excluded_tool_names is not None:
            self._excluded_tools.update(excluded_tool_names)
            self._excluded_tools.add("spawn_subagent")
        if tool_space is not None:
            self._tool_space = tool_space
        if tool_runtime_config is not None:
            self._tool_runtime_config = tool_runtime_config

retrieve_tools: StructuredTool | None = None
store_arg = None
if not disable_retrieve_tools:
    if retrieve_tools_function is None and retrieve_tools_coroutine is None:
        retrieve_tools_function, retrieve_tools_coroutine = get_default_retrieval_tool(
            namespace_prefix, limit=limit, filter=filter
        )
    retrieve_tools = StructuredTool.from_function(
        func=retrieve_tools_function, coroutine=retrieve_tools_coroutine
    )
    store_arg = get_store_arg(retrieve_tools)

def build_tools_to_bind(state: State) -> list[BaseTool]:
    """Assemble the bound-tool list with a cache-stable ordering.

    Fixed tools (``retrieve_tools``, the agent's initial set, middleware)
    are bound first so they form a byte-stable prefix for the whole
    conversation. Dynamically retrieved tools (``selected_tool_ids``, which
    only ever grows via the append-only reducer) are bound LAST, so each
    retrieval appends to the tail instead of shifting the fixed tools. That
    keeps the request's function-declaration prefix stable and lets the
    provider's implicit prompt cache survive across turns instead of
    resetting on every tool retrieval.
    """
    # Skip unknown ids (a stale id in the append-only selected_tool_ids must
    # not crash the model invocation) rather than indexing blindly.
    initial_tools = [
        tool_registry[id] for id in (initial_tool_ids or []) if id in tool_registry
    ]
    selected_tools = [
        tool_registry[id] for id in state["selected_tool_ids"] if id in tool_registry
    ]
    tools_to_bind: list[BaseTool] = []
    if retrieve_tools is not None:
        tools_to_bind.append(retrieve_tools)
    tools_to_bind.extend(initial_tools)
    tools_to_bind.extend(middleware_tools)
    tools_to_bind.extend(selected_tools)
    return dedupe_tool_bindings(tools_to_bind)

def call_model(state: State, config: RunnableConfig, *, store: BaseStore) -> State:
    state = sync_execute_hooks(pre_model_hooks, state, config, store)

    if middleware_executor:
        raise RuntimeError(
            "Agent middleware is configured but sync execution was requested. "
            "Use the async graph execution path (ainvoke/astream)."
        )

    model_configurations = config.get("configurable", {})
    _llm = llm.with_config(configurable=model_configurations)
    llm_with_tools = _llm.bind_tools(build_tools_to_bind(state))  # type: ignore[attr-defined]
    response = llm_with_tools.invoke(state["messages"])

    if not response.tool_calls and not response.content:
        response.content = "Empty response from model."

    if isinstance(response.content, str) and agent_name == "comms_agent":
        response.content = response.content + NEW_MESSAGE_BREAKER

    return {"messages": [response]}  # type: ignore[return-value]

async def acall_model(state: State, config: RunnableConfig, *, store: BaseStore) -> State:
    """Async model invocation with middleware support."""
    state = await execute_hooks(pre_model_hooks, state, config, store)

    if middleware_executor:
        state = await middleware_executor.execute_before_model(state, config, store)

    model_configurations = config.get("configurable", {})
    _llm = llm.with_config(configurable=model_configurations)

    tools_to_bind = build_tools_to_bind(state)
    llm_with_tools = _llm.bind_tools(tools_to_bind)  # type: ignore[attr-defined]

    try:
        recent_messages = state.get("messages", [])[-6:]
        preview = []
        for msg in recent_messages:
            role = msg.__class__.__name__
            content = getattr(msg, "content", "")
            if isinstance(content, str) and len(content) > 200:
                content = content[:197] + "..."
            preview.append({"role": role, "content": content})
        log.info("acall_model message preview", preview=preview)
    except Exception as e:
        log.debug(f"Failed to log message preview: {e}")

    if middleware_executor and middleware_executor.has_wrap_model_call():
        middleware_tools_for_request: list[BaseTool | dict[str, Any]] = [
            tool for tool in tools_to_bind
        ]
        response = await middleware_executor.wrap_model_invocation(
            model=_llm,  # type: ignore[arg-type]
            state=state,
            config=config,
            store=store,
            tools=middleware_tools_for_request,
            invoke_fn=llm_with_tools.ainvoke,
        )
    else:
        response = await llm_with_tools.ainvoke(state["messages"])

    if not response.tool_calls and not response.content:
        response.content = "Empty response from model."

    if isinstance(response.content, str) and agent_name == "comms_agent":
        response.content = response.content + NEW_MESSAGE_BREAKER

    # Build updated state with response for after_model hooks
    updated_state: State = dict(state)  # type: ignore[assignment]
    updated_state["messages"] = list(state.get("messages", [])) + [response]

    # Execute middleware after_model hooks
    if middleware_executor:
        updated_state = await middleware_executor.execute_after_model(
            updated_state, config, store
        )

    # Return partial state update: new message + any keys added by
    # after_model (e.g. todos). Messages use an append reducer, so only
    # return the new response — not the full list.
    result: dict[str, object] = {"messages": [response]}
    base_keys = {"messages", "selected_tool_ids"}
    for key, value in updated_state.items():
        if key not in base_keys:
            result[key] = value
    return result  # type: ignore[return-value]

def select_tools(tool_calls: list[dict], config: RunnableConfig, *, store: BaseStore) -> State:
    if retrieve_tools is None:
        raise RuntimeError("retrieve_tools is disabled and select_tools should not be called")

    selected_tools = {}
    response_tools = {}
    for tool_call in tool_calls:
        kwargs = {**tool_call["args"]}
        if store_arg:
            kwargs[store_arg] = store
        if config:
            user_id = config.get("configurable", {}).get("user_id")
            if user_id:
                kwargs["user_id"] = user_id

        result = retrieve_tools.invoke(kwargs, config=config)

        # Handle both RetrieveToolsResult dict and plain list
        if isinstance(result, dict):
            tools_to_bind = [
                tool_id
                for tool_id in result.get("tools_to_bind", [])
                if isinstance(tool_id, str)
            ]
            response = [
                tool_id for tool_id in result.get("response", []) if isinstance(tool_id, str)
            ]
        else:
            tools_to_bind = [
                tool_id
                for tool_id in (result if isinstance(result, list) else [])
                if isinstance(tool_id, str)
            ]
            response = tools_to_bind

        # Filter out subagent: prefixed tools from binding
        filtered_bind = [
            tool_id for tool_id in tools_to_bind if not tool_id.startswith("subagent:")
        ]
        selected_tools[tool_call["id"]] = dedupe_str_list(filtered_bind)
        response_tools[tool_call["id"]] = dedupe_str_list(response)

    tool_messages, _ = format_selected_tools(response_tools, tool_registry)  # type: ignore[arg-type]
    _, bind_ids = format_selected_tools(selected_tools, tool_registry)  # type: ignore[arg-type]
    return {"messages": tool_messages, "selected_tool_ids": bind_ids}  # type: ignore[return-value]

